module register(
	input wire clk,
	input wire reset,
	input wire en,
	input wire [7:0] D,
	output reg [7:0] Q
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
	if (reset)
		Q <= 8'b0;
	else if (en)
		Q <= D;
end
endmodule
